KP_MAP["iron_carbon_diagram"] = {"key": "iron_carbon_diagram", "name": "铁碳相图", "explanation": "铁碳相图是热处理的基础。关键点：①共析点（0.77%C, 727°C）发生珠光体转变；②共晶点（4.3%C, 1148°C）发生莱氏体转变；③亚共析钢（<0.77%C）组织为铁素体+珠光体，过共析钢（0.77%~2.11%C）组织为珠光体+二次渗碳体；④A1/A3/Acm 三条临界线是制定加热温度的依据。", "key_concepts": ["共析转变", "共晶转变", "A1/A3/Acm线", "亚共析/共析/过共析", "杠杆定律计算相组成"], "exam_focus": "常考：含碳量与组织的关系、相组成计算、临界线含义及应用"};
KP_MAP["steel_classification"] = {"key": "steel_classification", "name": "钢的分类与牌号", "explanation": "钢按含碳量分为低碳钢（<0.25%）、中碳钢（0.25%~0.6%）、高碳钢（>0.6%）；按合金元素含量分为低合金钢（<5%）、中合金钢（5%~10%）、高合金钢（>10%）；按用途分为结构钢、工具钢、特殊性能钢。牌号含义如 T10A=平均含碳量1.0%的高级优质碳素工具钢；40Cr=含碳0.40%的铬合金结构钢。", "key_concepts": ["按含碳量分类", "按合金含量分类", "按用途分类", "牌号命名规则", "常见牌号识别"], "exam_focus": "常考：20/45/T8/T12/40Cr/GCr15/W18Cr4V 等常见牌号的分类和含碳量"};
KP_MAP["alloy_elements"] = {"key": "alloy_elements", "name": "合金元素作用", "explanation": "合金元素对钢的性能有显著影响：①S导致热脆性（高温下FeS熔化在晶界），P导致冷脆性（低温下磷化物脆化晶界）；②Mn提高强度和淬透性，Si提高强度和弹性极限；③Cr提高淬透性和耐腐蚀性，Ni提高低温韧性，Mo/W/V细化晶粒并提高红硬性；④多数合金元素（除Co外）使C曲线右移，提高淬透性。", "key_concepts": ["S-热脆性/P-冷脆性", "Mn/Si/Cr/Ni/Mo/W/V各自作用", "C曲线右移=提高淬透性", "回火脆性与合金元素的关系"], "exam_focus": "高频考点：S→热脆、P→冷脆、合金元素对淬透性的影响"};
KP_MAP["annealing"] = {"key": "annealing", "name": "退火", "explanation": "退火是将钢加热到适当温度，保温后缓慢冷却（通常炉冷）的热处理工艺。目的：降低硬度、消除内应力、改善切削加工性、细化晶粒、为后续热处理做准备。常见类型：①完全退火（加热到Ac3以上30~50°C）；②球化退火（用于共析/过共析钢，使渗碳体球化）；③去应力退火（500~650°C，无相变）；④再结晶退火（用于冷变形金属）。", "key_concepts": ["退火温度选择", "球化退火对象", "去应力退火无相变", "完全退火与不完全退火区别", "退火后缓慢冷却"], "exam_focus": "常考：各种退火的适用对象、温度范围、去应力退火组织不变"};
KP_MAP["normalizing"] = {"key": "normalizing", "name": "正火", "explanation": "正火是将钢加热到Ac3或Accm以上30~50°C，保温后在空气中冷却。目的：细化晶粒、消除网状渗碳体、改善切削加工性。与退火相比，正火冷却速度更快，得到的珠光体更细，强度和硬度更高。低碳钢常用正火代替退火，既提高性能又降低成本。球化退火前如存在网状渗碳体，应先正火消除。", "key_concepts": ["正火温度", "空冷", "细化晶粒", "消除网状渗碳体", "正火vs退火"], "exam_focus": "常考：正火与退火的区别、正火代替退火的条件、球化退火前正火的必要性"};
KP_MAP["quenching"] = {"key": "quenching", "name": "淬火", "explanation": "淬火是将钢加热到临界温度以上奥氏体化，保温后以大于临界冷却速度快速冷却，获得马氏体（或贝氏体）组织。目的：提高硬度和耐磨性。淬火温度：亚共析钢=Ac3+30~50°C，过共析钢=Ac1+30~50°C。冷却介质选择原则：在C曲线鼻子处快冷避免珠光体转变，在Ms点以下慢冷减少变形开裂。淬透性≠淬硬性：淬透性是获得马氏体层深度的能力，淬硬性是能达到的最高硬度。", "key_concepts": ["淬火温度选择", "临界冷却速度", "淬透性vs淬硬性", "冷却介质选择", "马氏体转变"], "exam_focus": "高频考点：淬火温度（亚共析vs过共析）、淬透性与淬硬性的区别、双液淬火"};
KP_MAP["tempering"] = {"key": "tempering", "name": "回火", "explanation": "回火是将淬火钢加热到A1以下温度，保温后冷却。目的：消除淬火应力、调整硬度与韧性的配合、稳定组织。①低温回火（150~250°C）：得回火马氏体，用于工具、量具、渗碳件；②中温回火（350~500°C）：得回火托氏体，用于弹簧；③高温回火（500~650°C）：得回火索氏体，用于调质处理的结构件。淬火+高温回火=调质处理。注意回火脆性区间（250~400°C和450~650°C慢冷）。", "key_concepts": ["三种回火温度区间及组织", "调质=淬火+高温回火", "回火脆性", "二次硬化", "回火稳定性"], "exam_focus": "高频考点：调质处理定义、三种回火组织与应用、回火脆性温度区间"};
KP_MAP["surface_chemical_heat_treatment"] = {"key": "surface_chemical_heat_treatment", "name": "表面与化学热处理", "explanation": "表面热处理只改变表层组织（如感应淬火、火焰淬火），化学热处理改变表层化学成分和组织（如渗碳、渗氮、碳氮共渗）。渗碳：在920~950°C将碳渗入低碳钢表面，渗后淬火+低温回火，表层高碳马氏体（高硬度耐磨）+心部低碳（韧性好）。渗氮：在500~550°C渗氮，渗后不需淬火即获得高硬度。渗碳层深度常用公式：d=K√t（K为渗碳系数，t为时间）。", "key_concepts": ["渗碳温度", "渗碳层公式 d=K√t", "渗氮不淬火即高硬度", "感应淬火vs火焰淬火", "表面淬火+化学热处理区别"], "exam_focus": "常考：渗碳温度和后续热处理、渗碳层深度计算、渗氮与渗碳的区别"};
KP_MAP["ttt_cct_diagram"] = {"key": "ttt_cct_diagram", "name": "C曲线与TTT图", "explanation": "C曲线（TTT图）描述过冷奥氏体等温转变的规律。C形曲线的鼻子处（~550°C）孕育期最短，最不稳定。C曲线越靠右→过冷奥氏体越稳定→淬透性越好。影响C曲线的因素：①含碳量（亚共析钢C曲线偏左，共析钢最右）；②合金元素（除Co外均使C曲线右移）；③加热温度和保温时间（温度越高/时间越长，C曲线右移）。CCT图是连续冷却转变图，更接近实际生产。", "key_concepts": ["C曲线形状含义", "鼻子温度~550°C", "合金元素使C曲线右移", "TTT vs CCT", "临界冷却速度"], "exam_focus": "常考：C曲线位置影响因素、为什么合金钢淬透性好、孕育期概念"};
KP_MAP["austenite_transformation"] = {"key": "austenite_transformation", "name": "奥氏体转变", "explanation": "钢加热到Ac1以上时发生奥氏体转变（珠光体→奥氏体），此过程经历形核、长大、残余渗碳体溶解、奥氏体均匀化四个阶段。奥氏体晶粒度分为：起始晶粒度（刚形成时）、实际晶粒度（交货状态）、本质晶粒度（特定条件下晶粒长大倾向）。本质细晶粒钢在930°C以下加热晶粒不易长大。过冷奥氏体是指在A1以下仍未转变的奥氏体，处于亚稳态。", "key_concepts": ["奥氏体形成四阶段", "三种晶粒度的区别", "过冷奥氏体概念", "本质晶粒度", "加热温度与晶粒长大"], "exam_focus": "常考：实际晶粒度/本质晶粒度定义、过冷奥氏体概念"};
KP_MAP["martensite_transformation"] = {"key": "martensite_transformation", "name": "马氏体转变", "explanation": "马氏体转变是非扩散型转变（切变共格），转变速度极快。马氏体是碳在α-Fe中的过饱和固溶体，硬度高但脆性大。Ms点（马氏体开始转变温度）和Mf点（转变终了温度）随含碳量增加而降低。高碳马氏体为片状（针状），低碳马氏体为板条状。残余奥氏体量随Ms点降低而增加（高碳钢/合金钢残余奥氏体多）。", "key_concepts": ["非扩散型切变转变", "Ms/Mf点与含碳量关系", "板条马氏体vs片状马氏体", "残余奥氏体"], "exam_focus": "常考：马氏体转变是非扩散的、含碳量与Ms点的关系"};
KP_MAP["pearlite_bainite"] = {"key": "pearlite_bainite", "name": "珠光体与贝氏体转变", "explanation": "珠光体转变属于扩散型转变，贝氏体转变属于半扩散型转变。过冷奥氏体高温转变产物→珠光体（粗片层，A1~650°C）→索氏体（细片层，650~600°C）→托氏体（极细片层，600~550°C），三者本质都是铁素体+渗碳体的机械混合物，只是片层间距不同。贝氏体：上贝氏体（550~350°C，羽毛状，性能差）和下贝氏体（350°C~Ms，针状，综合性能好）。珠光体相组成：铁素体+渗碳体。", "key_concepts": ["珠光体/索氏体/托氏体=片层间距不同", "上贝氏体vs下贝氏体", "扩散vs半扩散vs非扩散", "珠光体相组成"], "exam_focus": "高频考点：三种珠光体类组织的区别、贝氏体转变温度区间"};
KP_MAP["mechanical_properties"] = {"key": "mechanical_properties", "name": "力学性能", "explanation": "常用力学性能指标：①强度（抵抗塑性变形和断裂的能力，σs屈服强度/σb抗拉强度）；②塑性（δ延伸率/ψ断面收缩率）；③硬度（抵抗局部压入的能力，常用HBW/HRC/HV）；④韧性（αk冲击韧性，抵抗冲击载荷）；⑤刚度（弹性模量E，抵抗弹性变形）。刚度取决于材料本质，不能通过热处理改变。位错运动是实现塑性变形的微观机制，冷变形使位错密度大增→加工硬化。", "key_concepts": ["强度/塑性/硬度/韧性/刚度定义", "弹性变形vs塑性变形", "位错与塑性变形", "加工硬化", "布氏/洛氏/维氏硬度适用范围"], "exam_focus": "高频考点：刚度不能热处理改变、韧性vs塑性区别、硬度单位、位错密度与冷变形"};
KP_MAP["heat_treatment_equipment"] = {"key": "heat_treatment_equipment", "name": "热处理设备", "explanation": "热处理设备包括加热设备（箱式炉、井式炉、台车炉、盐浴炉、真空炉、气氛炉等）、冷却设备（淬火槽、冷却循环系统）、辅助设备（吊车、机械手、工装料框等）。关键部件：加热元件（电阻带/电炉丝/硅碳棒）、循环风机（保证炉温均匀性）、热电偶（测温）、控制柜。炉温均匀性是衡量炉子质量的核心指标。安全操作要求：吊具不得悬挂、控制柜门不得常开、出炉不得立即关停循环风机等。", "key_concepts": ["加热炉类型", "循环风机作用=炉温均匀", "加热元件类型", "淬火槽冷却系统", "设备安全操作"], "exam_focus": "常考：炉子类型识别、炉温均匀性、TPM/自主维护、设备安全操作规范"};
